class TOCSticky{constructor(tocElement){this.tocElement=tocElement;this.toggleBtn=tocElement.querySelector(".toc-toggle");this.tocNav=tocElement.querySelector(".toc-nav");this.isOpen=true;this.isMobile=null;this.init()}init(){if(this.toggleBtn){this.toggleBtn.addEventListener("click",()=>this.toggleToc())}window.addEventListener("resize",()=>this.handleResize());this.setInitialState();this.setupScrollTracking()}setInitialState(){const newIsMobile=window.innerWidth<1024;if(newIsMobile===this.isMobile)return;this.isMobile=newIsMobile;if(this.isMobile){this.closeToc()}else{this.openToc()}}handleResize(){this.setInitialState()}toggleToc(){if(this.isOpen){this.closeToc()}else{this.openToc()}}closeToc(){this.isOpen=false;this.tocElement.classList.add("is-closed");this.tocNav.setAttribute("aria-hidden","true");this.toggleBtn.setAttribute("aria-expanded","false");this.toggleBtn.innerHTML='<span class="toc-toggle-icon">☰</span>'}openToc(){this.isOpen=true;this.tocElement.classList.remove("is-closed");this.tocNav.setAttribute("aria-hidden","false");this.toggleBtn.setAttribute("aria-expanded","true");this.toggleBtn.innerHTML='<span class="toc-toggle-icon">✕</span>'}setupScrollTracking(){const observer=new IntersectionObserver(entries=>{entries.forEach(entry=>{if(entry.isIntersecting){this.setActiveLink(entry.target.id)}})},{rootMargin:"0px 0px -50% 0px",threshold:0});const contentEntry=document.querySelector(".content__entry");if(contentEntry){const headings=contentEntry.querySelectorAll("h2, h3, h4, h5, h6");headings.forEach(heading=>{observer.observe(heading)})}}setActiveLink(headingId){this.tocElement.querySelectorAll(".toc-nav a").forEach(link=>{link.classList.remove("is-active")});const activeLink=this.tocElement.querySelector(`.toc-nav a[href="#${headingId}"]`);if(activeLink){activeLink.classList.add("is-active")}}}